    choice = edit.note.content.get('verification', {}).get('value')
    comments = edit.note.content.get('revision_comments', {}).get('value', '').strip()
    if choice == 'Request camera-ready revision' and not comments:
        raise openreview.OpenReviewException('Revision comments are required when requesting a camera-ready revision.')

invitation.process:
def process(client, edit, invitation):
    script = None
    for parent_invitation_id in invitation.invitations or []:
        parent_invitation = client.get_invitation(parent_invitation_id)
        parent_content = getattr(parent_invitation, 'content', {}) or {}
        if 'process_script' in parent_content:
            script = parent_content['process_script']['value']
            break
    if script is None:
        raise openreview.OpenReviewException(f'Camera-ready verification invitation {invitation.id} has no parent process_script.')
    funcs = {
        'openreview': openreview,
        'datetime': datetime
    }
    exec(script, funcs)
    funcs['process'](client, edit, invitation)
